import React from 'react'; 
import Login from './pages/Login'; 
import Dashboard from './components/Dashboard/Dashboard'; 
 
function App() { 
  const token = localStorage.getItem('token'); 
 
  return token ? <Dashboard /> : <Login />; 
} 
 
export default App;
